module spi_memory_interface (
    input  wire        clk,           // System clock
    input  wire        spi_rst_n,       // Reset
    input  wire        st,            // Store (write) signal
    input  wire        ld,            // Load (read) signal
    input  wire [15:0] addr,          // 16-bit memory address
    input  wire [15:0] data_in,       // 16-bit data input (for write)
    output reg  [15:0] data_out,      // 16-bit data output (for read)
    output reg         spi_cs,        // SPI Chip Select (Active Low)
    output reg         spi_clk,       // SPI Clock
    output reg         busy,          // Busy signal
    output reg         spi_mosi,      // SPI MOSI (Master Out Slave In)
    input  wire        spi_miso      // SPI MISO (Master In Slave Out)

  );

  // Define FSM states

  localparam  IDLE = 4'b0000;
  localparam  START = 4'b0001;
  localparam  SEND_CMD = 4'b0010;
  localparam  SEND_ADDR = 4'b0011;
  localparam  WRITE_DATA = 4'b0100;
  localparam  READ_DATA = 4'b0101;
  localparam  STOP = 4'b0110;
  localparam  TOGGLECLKON = 4'b0111;
  localparam  decideFate = 4'b1000;

  localparam  STcom = 1;
  localparam  LDcom = 0;


  reg[4:0] state;
  reg[4:0] last_state;
  reg command;

  reg [7:0] shift_reg; // Shift register for SPI data
  reg [5:0] bit_cnt;   // Bit counter
  reg [2:0] byte_cnt;  // Byte counter
  reg [15:0] recv_data;// Temporary storage for received data

  reg [0:0] prev_command;
  reg [15:0] prev_addr;
  wire [23:0] spi_addr;
  assign spi_addr = {7'b0000000, addr, 1'b0};

  always @(posedge clk , negedge spi_rst_n)
  begin

    if (!spi_rst_n)
    begin
      state   <= IDLE;
      spi_cs  <= 1'b1;
      spi_clk <= 1'b0;
      spi_mosi <= 1'b0;
      busy    <= 1'b0;
      bit_cnt <= 3'b000;
      byte_cnt <= 3'b000;
      command <= STcom;
      state <= IDLE;
      last_state <= IDLE;
    end
    else
    begin
      case (state)
        IDLE:
        begin
          busy <= 1'b0;
          if (st || ld)
          begin
            state <= START;
            busy <= 1'b1;

            prev_command <= command;
            prev_addr <= addr;

            if (st)
            begin
              shift_reg <= 8'h02; // Write command
              command <= STcom;
            end

            else if (ld)
            begin
              shift_reg <= 8'h03; // Read command
              command <= LDcom;
            end

          end
        end

        START:
        begin
          spi_cs <=1'b0;
          bit_cnt <= 3'b000;
          byte_cnt <= 3'b000;
          state <= SEND_CMD;
        end

        SEND_CMD:
        begin
          spi_clk <= 0;
          if (bit_cnt < 8)
          begin
            spi_mosi <= shift_reg[7];   // Send MSB first
            shift_reg <= shift_reg << 1;
            last_state <= state;
            state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
          end
          else
          begin
            state <= SEND_ADDR;
            shift_reg <= spi_addr[23:16] ;         // top address byte for 24-bit SPI flash
            bit_cnt <= 0;
            byte_cnt <= 0;
          end
        end

        SEND_ADDR:
        begin
          spi_clk <= 0;

          if (bit_cnt < 8)
          begin
            spi_mosi <= shift_reg[7];
            shift_reg <= shift_reg << 1;
            last_state <= state;
            state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
          end
          else if (byte_cnt == 0)
          begin
            shift_reg <= spi_addr[15:8];    // middle address byte
            byte_cnt <= 1;
            bit_cnt <= 0;
          end
          else if (byte_cnt == 1)
          begin
            shift_reg <= spi_addr[7:0];     // low address byte
            byte_cnt <= 2;
            bit_cnt <= 0;
          end
          else
          begin
            state <= command ? WRITE_DATA : READ_DATA;
            shift_reg <= command ? data_in[15:8] : 8'h00;
            recv_data <= 16'h0000;
            bit_cnt <= 0;
            byte_cnt <= 0;
            spi_mosi <= 1'b0;
          end
        end

        WRITE_DATA:
        begin

          spi_clk <= 0;
          if (bit_cnt < 8)
          begin
            spi_mosi <= shift_reg[7];
            shift_reg <= shift_reg << 1;

            last_state <= state;
            state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
          end
          else if (byte_cnt == 0)
          begin
            shift_reg <= data_in[7:0]; // Load low byte
            byte_cnt <= 1;
            bit_cnt <= 0;
          end
          else
          begin
            state <= decideFate; // Decide next state based on command
          end
        end

        READ_DATA:
        begin

          spi_clk <= 0;
          if (bit_cnt < 17)
          begin
            last_state<=state;

            if (bit_cnt<16)
              state <= TOGGLECLKON;
            bit_cnt <= bit_cnt + 1;
            recv_data[15:0] <= {recv_data[14:0], spi_miso}; // Shift left


          end
          else
          begin
            recv_data[15:0] <= {recv_data[14:0], spi_miso};
            data_out <= recv_data;
            state <= decideFate; // Decide next state based on command
            bit_cnt <= 0;
          end
        end


        STOP:
        begin

          spi_clk <= 0;
          spi_cs <= 1'b1;
          busy <= 1'b0;
          state <= IDLE;
        end

        TOGGLECLKON:
        begin
          spi_clk <= 1;
          state <= last_state;
        end

        decideFate:
        begin
          if (command == prev_command &&
              addr == prev_addr + 1 )
          begin
            // Continue without releasing CS
            shift_reg <= command ? data_in[15:8] : 8'h00;
            bit_cnt <= 0;
            byte_cnt <= 0;
            recv_data <= 0;
            spi_mosi <= 0;
            state <= command ? WRITE_DATA : READ_DATA;

            // Update previous address
            prev_addr <= addr;
          end
          else
          begin
            // End transaction
            state <= STOP;
          end
        end
        default :
          state <= STOP;

      endcase
    end

  end

endmodule

module interrupt_controller_small (
    input  [3:0] dOut,
    input  [15:0] Addr,
    input         ioW,
    input         C,
    input         rst_n,

    input  [2:0]  irq_in,
    input         imm,
    input         reti,
    input         pc_en,

    input  [15:0] CPUInterruptEnableAddr,
    input  [15:0] inputInterruptAddr,
    input  [15:0] interruptRegAddr,

    output [15:0] InterruptOut,
    output        intr,
    output        irq_lock
);

  reg       global_enable;
  reg       irq_lock_r   ;
  reg [2:0] irq_enable   ;
  reg [2:0] irq_pending  ;

  wire wr_ctrl;
  wire wr_enable;
  wire wr_pending;

  wire rd_ctrl;
  wire rd_enable;
  wire rd_pending;

  wire [2:0] pending_with_new_irq;
  wire [2:0] active_irq;
  wire       intr_take;

  assign wr_ctrl    = ioW && (Addr == CPUInterruptEnableAddr);
  assign wr_enable  = ioW && (Addr == inputInterruptAddr);
  assign wr_pending = ioW && (Addr == interruptRegAddr);

  assign rd_ctrl    =  (Addr == CPUInterruptEnableAddr);
  assign rd_enable  =  (Addr == inputInterruptAddr);
  assign rd_pending =  (Addr == interruptRegAddr);

  assign pending_with_new_irq = irq_pending | irq_in;
  assign active_irq           = irq_pending & irq_enable;

  assign intr      = global_enable && !irq_lock_r && !imm && (active_irq != 4'b0000);
  assign irq_lock  = irq_lock_r;
  assign intr_take = intr && pc_en;

  always @(posedge C or negedge rst_n)
  begin
    if (!rst_n)
    begin
      global_enable <= 1'b0;
      irq_lock_r    <= 1'b0;
      irq_enable    <= 4'b0000;
      irq_pending   <= 4'b0000;
    end
    else
    begin
      // default: latch new interrupt requests
      irq_pending <= pending_with_new_irq;

      // global interrupt enable
      if (wr_ctrl)
        global_enable <= dOut[0];

      // source enable bits [3:0]
      if (wr_enable)
        irq_enable <= dOut[3:0];

      // write 1 to clear pending bits
      if (wr_pending)
        irq_pending <= pending_with_new_irq & ~dOut[2:0];

      // lock once interrupt is actually taken
      if (intr_take)
        irq_lock_r <= 1'b1;

      // unlock only on RETI
      if (reti)
        irq_lock_r <= 1'b0;
    end
  end

  assign InterruptOut =
      rd_ctrl    ? {13'h0000, intr, irq_lock_r, global_enable} :
      rd_enable  ? {13'h000, irq_enable} :
      rd_pending ? {13'h000, irq_pending} :
      16'h0000;

endmodule
module lfsr_RandomNumberGen (
    input  [15:0] adrrIn,
    input  [7:0] dataIn,
    input         ioW,
    input         clk,
    input  [15:0] SeedAdr,
    input  [15:0] RngAdr,
    output [15:0] Out
);

    reg [7:0] seed_reg;
    reg [7:0] lfsr    ;

    wire seed_wr  = ioW && (adrrIn == SeedAdr);
    wire seed_rd  =  (adrrIn == SeedAdr);
    wire rng_rd   =  (adrrIn == RngAdr);

    // 8-bit maximal-length taps
    // polynomial: x^8 + x^6 + x^5 + x^4 + 1
    wire feedback = lfsr[7] ^ lfsr[5] ^ lfsr[4] ^ lfsr[3];

    always @(posedge clk) begin
        if (seed_wr) begin
            seed_reg <= dataIn[7:0];
            lfsr <= (dataIn[7:0] == 8'h00) ? 8'h01 : dataIn[7:0];
        end else begin
            lfsr <= {lfsr[6:0], feedback};
        end
    end

    assign Out = seed_rd ? {8'h00, seed_reg} :
                 rng_rd  ? {8'h00, lfsr}     :
                           16'h0000;

endmodule
module timer (
    input  [15:0] dOut,
    input  [15:0] Addr,
    input         ioW,
    input         C,
    input         InterLock,
    input  [15:0] timerConfigAddr,
    input  [15:0] timerTargetAddr,
    input  [15:0] timerResetAddr,
    input  [15:0] timerReadAddr,
    input  [15:0] timerSyncStartAddr,
    input         rst_n,
    output [15:0] TimerOut,
    output        timer_interrupt
  );

  reg [15:0] target       ;
  reg [15:0] count        ;
  reg [10:0] prescale_cnt ;
  reg [6:0]  conf         ;

  wire wr_conf   = ioW && (Addr == timerConfigAddr);
  wire wr_target = ioW && (Addr == timerTargetAddr);
  wire wr_reset  = ioW && (Addr == timerResetAddr) && dOut[0];
  wire wr_sync_start = ioW && (Addr == timerSyncStartAddr);

  wire rd_count  =  (Addr == timerReadAddr);
  wire rd_target =  (Addr == timerTargetAddr);
  wire rd_conf   =  (Addr == timerConfigAddr);

  wire       timer_en     = conf[0];
  wire [3:0] prescaler    = conf[4:1];
  wire       auto_reload  = conf[5];
  wire       irq_en       = conf[6];
  wire       target_valid = (target != 16'h0000);
  wire       matched      = target_valid && (count == target);

  reg tick;
  always @(*)
  begin
    case (prescaler)
      4'd0:
        tick = 1'b1;                  // /1
      4'd1:
        tick = prescale_cnt[0];       // /2
      4'd2:
        tick = &prescale_cnt[1:0];    // /4
      4'd3:
        tick = &prescale_cnt[2:0];    // /8
      4'd4:
        tick = &prescale_cnt[3:0];    // /16
      4'd5:
        tick = &prescale_cnt[4:0];    // /32
      4'd6:
        tick = &prescale_cnt[5:0];    // /64
      4'd7:
        tick = &prescale_cnt[6:0];    // /128
      4'd8:
        tick = &prescale_cnt[7:0];    // /256
      4'd9:
        tick = &prescale_cnt[8:0];    // /512
      4'd10:
        tick = &prescale_cnt[9:0];    // /1024
      default:
        tick = 1'b1;
    endcase
  end

  always @(posedge C or negedge rst_n)
  begin
    if (!rst_n)
    begin
      target       <= 16'h0000;
      count        <= 16'h0000;
      prescale_cnt <= 11'h000;
      conf         <= 7'h00;
    end
    else
    begin
      if (wr_conf)
      begin
        conf         <= dOut[6:0];
        prescale_cnt <= 11'h000;
      end

      if (wr_target)
        target <= dOut;

      if (wr_sync_start)
        conf[0] <= dOut[0];

      if (wr_reset)
      begin
        count        <= 16'h0000;
        conf         <=7'h00;
      end
      else
      begin
        if (timer_en)
          prescale_cnt <= prescale_cnt + 11'd1;

        if (timer_en && !InterLock)
        begin
          if (matched)
          begin
            if (auto_reload)
              count <= 16'h0000;
          end
          else if (tick)
          begin
            count <= count + 16'd1;
          end
        end
      end
    end
  end

  assign TimerOut = rd_count  ? count             :
         rd_target ? target            :
         rd_conf   ? {9'h000, conf}   :
         16'h0000;

  assign timer_interrupt = irq_en && !InterLock && matched;

endmodule

