            3'h5: out = in_5;
            3'h6: out = in_6;
            3'h7: out = in_7;
            default:
                out = 'h0;
        endcase
    end
endmodule

module i2c_master_ctrl (
    input              clk,
    input              rst_n,

    input              wr_en,
    input      [3:0]   reg_addr,
    input      [15:0]  cpu_din,
    output reg [15:0]  cpu_dout,

    input              sda_in,
    input              scl_in,
    output             sda_out,
    output             scl_out,
    output reg         sda_oe,
    output reg         scl_oe,

    output             interrupt
);

assign sda_out = 1'b0;
assign scl_out = 1'b0;
assign interrupt = irq_enable & irq_pending;

localparam ST_IDLE       = 4'd0;
localparam ST_START_1    = 4'd1;
localparam ST_START_2    = 4'd2;
localparam ST_START_3    = 4'd3;
localparam ST_BIT_SETUP  = 4'd4;
localparam ST_BIT_HIGH   = 4'd5;
localparam ST_BIT_LOW    = 4'd6;
localparam ST_ACK_SETUPW = 4'd7;
localparam ST_ACK_HIGHW  = 4'd8;
localparam ST_ACK_LOWW   = 4'd9;
localparam ST_ACK_SETUPR = 4'd10;
localparam ST_ACK_HIGHR  = 4'd11;
localparam ST_ACK_LOWR   = 4'd12;
localparam ST_STOP_1     = 4'd13;
localparam ST_STOP_2     = 4'd14;
localparam ST_STOP_3     = 4'd15;

reg        enable;
reg        irq_enable;
reg        stretch_enable;

reg        op_busy;
reg        bus_active;
reg        done;
reg        ack_error;
reg        rx_valid;
reg        irq_pending;

reg [15:0] prescale_reg;
reg [15:0] divcnt;
reg        sm_tick;

reg [7:0]  tx_data_reg;
reg [7:0]  rx_data_reg;

reg [7:0]  tx_shift;
reg [7:0]  rx_shift;
reg [3:0]  bit_count;

reg        cmd_start;
reg        cmd_stop;
reg        cmd_write;
reg        cmd_read;
reg        cmd_read_nack;

reg [3:0]  state;

wire launch_cmd;
assign launch_cmd = wr_en && (reg_addr == 4'h4) && !op_busy && enable &&
                    (cpu_din[0] || cpu_din[1] || cpu_din[2] || cpu_din[3]);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        enable         <= 1'b0;
        irq_enable     <= 1'b0;
        stretch_enable <= 1'b0;

        op_busy        <= 1'b0;
        bus_active     <= 1'b0;
        done           <= 1'b0;
        ack_error      <= 1'b0;
        rx_valid       <= 1'b0;
        irq_pending    <= 1'b0;

        prescale_reg   <= 16'd0;
        divcnt         <= 16'd0;
        sm_tick        <= 1'b0;

        tx_data_reg    <= 8'd0;
        rx_data_reg    <= 8'd0;
        tx_shift       <= 8'd0;
        rx_shift       <= 8'd0;
        bit_count      <= 4'd0;

        cmd_start      <= 1'b0;
        cmd_stop       <= 1'b0;
        cmd_write      <= 1'b0;
        cmd_read       <= 1'b0;
        cmd_read_nack  <= 1'b0;

        state          <= ST_IDLE;

        sda_oe         <= 1'b0;
        scl_oe         <= 1'b0;
    end else begin
        sm_tick <= 1'b0;

        if (op_busy) begin
            if (prescale_reg == 16'd0) begin
                sm_tick <= 1'b1;
            end else begin
                if (divcnt == 16'd0) begin
                    divcnt  <= prescale_reg;
                    sm_tick <= 1'b1;
                end else begin
                    divcnt <= divcnt - 16'd1;
                end
            end
        end else begin
            divcnt <= 16'd0;
        end

        if (wr_en) begin
            case (reg_addr)
                4'h0: begin
                    enable         <= cpu_din[0];
                    irq_enable     <= cpu_din[1];
                    stretch_enable <= cpu_din[2];
                end

                4'h1: begin
                    if (cpu_din[2]) done        <= 1'b0;
                    if (cpu_din[3]) ack_error   <= 1'b0;
                    if (cpu_din[4]) rx_valid    <= 1'b0;
                    if (cpu_din[5]) irq_pending <= 1'b0;
                end

                4'h2: begin
                    prescale_reg <= cpu_din;
                end

                4'h3: begin
                    tx_data_reg <= cpu_din[7:0];
                end
                default:begin

                    
                end
            endcase
        end

        if (launch_cmd) begin
            cmd_start     <= cpu_din[0];
            cmd_stop      <= cpu_din[1];
            cmd_write     <= cpu_din[2];
            cmd_read      <= cpu_din[3];
            cmd_read_nack <= cpu_din[4];

            done        <= 1'b0;
            ack_error   <= 1'b0;
            irq_pending <= 1'b0;

            tx_shift    <= tx_data_reg;
            rx_shift    <= 8'd0;
            bit_count   <= 4'd7;
            op_busy     <= 1'b1;

            if (cpu_din[0]) begin
                state  <= ST_START_1;
                sda_oe <= 1'b0;
                scl_oe <= 1'b0;
            end else if (cpu_din[2] || cpu_din[3]) begin
                state <= ST_BIT_SETUP;
                scl_oe <= 1'b1;
            end else if (cpu_din[1]) begin
                state  <= ST_STOP_1;
                sda_oe <= 1'b1;
                scl_oe <= 1'b1;
            end else begin
                op_busy <= 1'b0;
                done    <= 1'b1;
                irq_pending <= 1'b1;
                state   <= ST_IDLE;
            end
        end

        if (sm_tick && op_busy) begin
            case (state)
                ST_IDLE: begin
                    op_busy <= 1'b0;
                end

                ST_START_1: begin
                    sda_oe <= 1'b0;
                    scl_oe <= 1'b0;
                    if (sda_in && ((!stretch_enable) || scl_in)) begin
                        state <= ST_START_2;
                    end
                end

                ST_START_2: begin
                    sda_oe <= 1'b1; // SDA low while SCL high
                    scl_oe <= 1'b0;
                    state  <= ST_START_3;
                end

                ST_START_3: begin
                    scl_oe     <= 1'b1; // pull SCL low
                    bus_active <= 1'b1;

                    if (cmd_write || cmd_read) begin
                        state <= ST_BIT_SETUP;
                    end else if (cmd_stop) begin
                        state <= ST_STOP_1;
                    end else begin
                        done        <= 1'b1;
                        irq_pending <= 1'b1;
                        op_busy     <= 1'b0;
                        state       <= ST_IDLE;
                    end
                end

                ST_BIT_SETUP: begin
                    scl_oe <= 1'b1; // keep clock low during setup

                    if (cmd_write) begin
                        if (tx_shift[bit_count])
                            sda_oe <= 1'b0; // release for logic 1
                        else
                            sda_oe <= 1'b1; // drive low for logic 0
                    end else begin
                        sda_oe <= 1'b0; // read bit: release SDA
                    end

                    state <= ST_BIT_HIGH;
                end

                ST_BIT_HIGH: begin
                    scl_oe <= 1'b0; // release SCL high

                    if ((!stretch_enable) || scl_in) begin
                        if (cmd_read)
                            rx_shift[bit_count] <= sda_in;

                        state <= ST_BIT_LOW;
                    end
                end

                ST_BIT_LOW: begin
                    scl_oe <= 1'b1; // drive SCL low again

                    if (bit_count != 4'd0) begin
                        bit_count <= bit_count - 4'd1;
                        state     <= ST_BIT_SETUP;
                    end else begin
                        if (cmd_write)
                            state <= ST_ACK_SETUPW;
                        else
                            state <= ST_ACK_SETUPR;
                    end
                end

                ST_ACK_SETUPW: begin
                    sda_oe <= 1'b0; // slave drives ACK/NACK
                    scl_oe <= 1'b1;
                    state  <= ST_ACK_HIGHW;
                end

                ST_ACK_HIGHW: begin
                    scl_oe <= 1'b0;

                    if ((!stretch_enable) || scl_in) begin
                        if (sda_in)
                            ack_error <= 1'b1;

                        state <= ST_ACK_LOWW;
                    end
                end

                ST_ACK_LOWW: begin
                    scl_oe <= 1'b1;
                    sda_oe <= 1'b0;

                    if (cmd_stop) begin
                        state <= ST_STOP_1;
                    end else begin
                        done        <= 1'b1;
                        irq_pending <= 1'b1;
                        op_busy     <= 1'b0;
                        state       <= ST_IDLE;
                    end
                end

                ST_ACK_SETUPR: begin
                    scl_oe <= 1'b1;

                    if (cmd_read_nack)
                        sda_oe <= 1'b0; // NACK = release high
                    else
                        sda_oe <= 1'b1; // ACK = drive low

                    state <= ST_ACK_HIGHR;
                end

                ST_ACK_HIGHR: begin
                    scl_oe <= 1'b0;

                    if ((!stretch_enable) || scl_in) begin
                        state <= ST_ACK_LOWR;
                    end
                end

                ST_ACK_LOWR: begin
                    scl_oe      <= 1'b1;
                    sda_oe      <= 1'b0;
                    rx_data_reg <= rx_shift;
                    rx_valid    <= 1'b1;

                    if (cmd_stop) begin
                        state <= ST_STOP_1;
                    end else begin
                        done        <= 1'b1;
                        irq_pending <= 1'b1;
                        op_busy     <= 1'b0;
                        state       <= ST_IDLE;
                    end
                end

                ST_STOP_1: begin
                    sda_oe <= 1'b1; // SDA low
                    scl_oe <= 1'b1; // SCL low
                    state  <= ST_STOP_2;
                end

                ST_STOP_2: begin
                    sda_oe <= 1'b1; // keep SDA low
                    scl_oe <= 1'b0; // release SCL high

                    if ((!stretch_enable) || scl_in) begin
                        state <= ST_STOP_3;
                    end
                end

                ST_STOP_3: begin
                    sda_oe      <= 1'b0; // release SDA high
                    scl_oe      <= 1'b0;
                    bus_active  <= 1'b0;
                    done        <= 1'b1;
                    irq_pending <= 1'b1;
                    op_busy     <= 1'b0;
                    state       <= ST_IDLE;
                end

                default: begin
                    sda_oe      <= 1'b0;
                    scl_oe      <= 1'b0;
                    bus_active  <= 1'b0;
                    done        <= 1'b1;
                    ack_error   <= 1'b1;
                    irq_pending <= 1'b1;
                    op_busy     <= 1'b0;
                    state       <= ST_IDLE;
                end
            endcase
        end
    end
end

always @(*) begin
    cpu_dout = 16'd0;

    case (reg_addr)
        4'h0: begin
            cpu_dout[0] = enable;
            cpu_dout[1] = irq_enable;
            cpu_dout[2] = stretch_enable;
        end

        4'h1: begin
            cpu_dout[0] = op_busy;
            cpu_dout[1] = bus_active;
            cpu_dout[2] = done;
            cpu_dout[3] = ack_error;
            cpu_dout[4] = rx_valid;
            cpu_dout[5] = irq_pending;
        end

        4'h2: begin
            cpu_dout = prescale_reg;
        end

        4'h3: begin
            cpu_dout[7:0] = rx_data_reg;
        end

        4'h4: begin
            cpu_dout[0] = cmd_start;
            cpu_dout[1] = cmd_stop;
            cpu_dout[2] = cmd_write;
            cpu_dout[3] = cmd_read;
            cpu_dout[4] = cmd_read_nack;
        end

        default: begin
            cpu_dout = 16'd0;
        end
    endcase
end

endmodule
module debug_serial_frontend_tiny
(
    input  wire        cpu_clk,
    input  wire        rst_n,

    input  wire        dbg_clk,
    input  wire        dbg_data_in,
    output reg         dbg_data_out,
    output reg         dbg_data_oe,

    output reg         reg_wr,
    output reg  [3:0]  reg_addr,
    output reg  [15:0] reg_wdata,
    input  wire [15:0] reg_rdata
);

  localparam CMD_PING  = 4'h0;
  localparam CMD_READ  = 4'h1;
  localparam CMD_WRITE = 4'h2;

  localparam S_RX      = 2'd0;
  localparam S_EXEC    = 2'd1;
  localparam S_LOAD_TX = 2'd2;
  localparam S_TX      = 2'd3;

  reg [1:0]  state;
  reg [23:0] rx_shift;
  reg [4:0]  rx_count;
  reg [15:0] tx_shift;
  reg [4:0]  tx_count;

  reg [3:0]  cmd_hold;
  reg [3:0]  addr_hold;
  reg [15:0] wdata_hold;

  reg [1:0] dbg_clk_sync;
  reg [1:0] dbg_data_sync;

  wire dbg_clk_rise;
  wire dbg_clk_fall;
  wire [23:0] rx_next;
  wire [15:0] tx_word;

  assign dbg_clk_rise = (dbg_clk_sync == 2'b01);
  assign dbg_clk_fall = (dbg_clk_sync == 2'b10);
  assign rx_next      = {rx_shift[22:0], dbg_data_sync[1]};
  assign tx_word      = (cmd_hold == CMD_PING)  ? 16'hDB12 :
                        (cmd_hold == CMD_READ)  ? reg_rdata :
                        (cmd_hold == CMD_WRITE) ? 16'hACCE :
                                                  16'hEEEE;

  always @(posedge cpu_clk or negedge rst_n)
  begin
    if (!rst_n)
    begin
      state        <= S_RX;
      rx_shift     <= 24'h000000;
      rx_count     <= 5'd0;
      tx_shift     <= 16'h0000;
      tx_count     <= 5'd0;
      cmd_hold     <= 4'h0;
      addr_hold    <= 4'h0;
      wdata_hold   <= 16'h0000;
      dbg_clk_sync <= 2'b00;
      dbg_data_sync<= 2'b11;
      dbg_data_out <= 1'b1;
      dbg_data_oe  <= 1'b0;
      reg_wr       <= 1'b0;
      reg_addr     <= 4'h0;
      reg_wdata    <= 16'h0000;
    end
    else
    begin
      dbg_clk_sync  <= {dbg_clk_sync[0], dbg_clk};
      dbg_data_sync <= {dbg_data_sync[0], dbg_data_in};
      reg_wr        <= 1'b0;

      case (state)
        S_RX:
        begin
          dbg_data_oe  <= 1'b0;
          dbg_data_out <= 1'b1;

          if (dbg_clk_rise)
          begin
            if (rx_count == 5'd23)
            begin
              cmd_hold   <= rx_next[23:20];
              addr_hold  <= rx_next[19:16];
              wdata_hold <= rx_next[15:0];
              rx_count   <= 5'd0;
              state      <= S_EXEC;
            end
            else
            begin
              rx_shift <= rx_next;
              rx_count <= rx_count + 5'd1;
            end
          end
        end

        S_EXEC:
        begin
          reg_addr  <= addr_hold;
          reg_wdata <= wdata_hold;
          if (cmd_hold == CMD_WRITE)
            reg_wr <= 1'b1;
          state <= S_LOAD_TX;
        end

        S_LOAD_TX:
        begin
          tx_shift     <= tx_word;
          tx_count     <= 5'd0;
          dbg_data_oe  <= 1'b0;
          dbg_data_out <= 1'b1;

          if (dbg_clk_fall)
          begin
            dbg_data_oe  <= 1'b1;
            dbg_data_out <= tx_word[15];
            state        <= S_TX;
          end
        end

        S_TX:
        begin
          if (dbg_clk_fall)
          begin
            if (tx_count == 5'd15)
            begin
              dbg_data_oe  <= 1'b0;
              dbg_data_out <= 1'b1;
              state        <= S_RX;
            end
            else
            begin
              tx_shift     <= {tx_shift[14:0], 1'b0};
              dbg_data_out <= tx_shift[14];
              tx_count     <= tx_count + 5'd1;
            end
          end
        end

        default:
        begin
          state        <= S_RX;
          dbg_data_oe  <= 1'b0;
          dbg_data_out <= 1'b1;
        end
      endcase
    end
  end

endmodule

module cpu_cycle_controller_tiny
(
    input  wire clk,
    input  wire rst_n,

    input  wire fetch_done,
    input  wire data_done,

    input  wire ld,
    input  wire st,
    input  wire flash_ld,

    input  wire dbg_enable,
    input  wire dbg_halt_req,
    input  wire dbg_run_req,
    input  wire dbg_step_req,
    input  wire dbg_break_hit,
    input  wire dbg_break_after_exec,

    output wire fetch_req,
    output wire execute_now_pulse,
    output wire dbg_halted
);

  localparam S_REQ_FETCH  = 3'd0;
  localparam S_WAIT_FETCH = 3'd1;
  localparam S_EXECUTE    = 3'd2;
  localparam S_WAIT_DATA  = 3'd3;
  localparam S_HALTED     = 3'd4;

  reg [2:0] state;
  reg       halt_pending;
  reg       step_active;

  wire mem_op;
  wire stop_after_exec;

  assign mem_op           = ld | st | flash_ld;
  assign fetch_req        = (state == S_REQ_FETCH);
  assign execute_now_pulse= (state == S_EXECUTE);
  assign dbg_halted       = (state == S_HALTED);
  assign stop_after_exec  = dbg_enable & (halt_pending | step_active | dbg_break_after_exec);

  always @(posedge clk or negedge rst_n)
  begin
    if (!rst_n)
    begin
      state        <= S_REQ_FETCH;
      halt_pending <= 1'b0;
      step_active  <= 1'b0;
    end
    else if (!dbg_enable)
    begin
      halt_pending <= 1'b0;
      step_active  <= 1'b0;

      case (state)
        S_REQ_FETCH:  state <= S_WAIT_FETCH;
        S_WAIT_FETCH: if (fetch_done) state <= S_EXECUTE;
        S_EXECUTE:    state <= mem_op ? S_WAIT_DATA : S_REQ_FETCH;
        S_WAIT_DATA:  if (data_done) state <= S_REQ_FETCH;
        default:      state <= S_REQ_FETCH;
      endcase
    end
    else
    begin
      if (dbg_halt_req)
        halt_pending <= 1'b1;

      case (state)
        S_REQ_FETCH:
        begin
          if (dbg_halt_req)
          begin
            state        <= S_HALTED;
            halt_pending <= 1'b0;
            step_active  <= 1'b0;
          end
          else
            state <= S_WAIT_FETCH;
        end

        S_WAIT_FETCH:
        begin
          if (fetch_done)
          begin
            if (dbg_break_hit | halt_pending)
            begin
              state        <= S_HALTED;
              halt_pending <= 1'b0;
              step_active  <= 1'b0;
            end
            else
              state <= S_EXECUTE;
          end
        end

        S_EXECUTE:
        begin
          if (mem_op)
            state <= S_WAIT_DATA;
          else if (stop_after_exec)
          begin
            state        <= S_HALTED;
            halt_pending <= 1'b0;
            step_active  <= 1'b0;
          end
          else
            state <= S_REQ_FETCH;
        end

        S_WAIT_DATA:
        begin
          if (data_done)
          begin
            if (stop_after_exec)
            begin
              state        <= S_HALTED;
              halt_pending <= 1'b0;
              step_active  <= 1'b0;
            end
            else
              state <= S_REQ_FETCH;
          end
        end

        S_HALTED:
        begin
          halt_pending <= 1'b0;

          if (dbg_run_req)
          begin
            state       <= S_REQ_FETCH;
            step_active <= 1'b0;
          end
          else if (dbg_step_req)
          begin
            state       <= S_REQ_FETCH;
            step_active <= 1'b1;
          end
        end

        default:
        begin
          state        <= S_REQ_FETCH;
          halt_pending <= 1'b0;
          step_active  <= 1'b0;
        end
      endcase
    end
  end

endmodule

module memory_wait_controller_tiny
(
    input  wire        clk,
    input  wire        rst_n,

    input  wire        fetch_req,
    input  wire        ld_req,
    input  wire        st_req,
    input  wire        flash_req,

    input  wire [15:0] fetch_addr,
    input  wire [15:0] data_addr,
    input  wire [15:0] store_data,

    output reg  [15:0] mem_rdata,
    output reg         fetch_done,
    output reg         data_done,
    output reg         mem_stall,

    output reg         spi_st,
    output reg         spi_ld,
    output reg  [15:0] spi_addr,
    output reg  [15:0] spi_data_in,
    output reg         spi_target,
    input  wire [15:0] spi_data_out,
    input  wire        spi_busy
);

  localparam OP_NONE  = 2'd0;
  localparam OP_FETCH = 2'd1;
  localparam OP_LOAD  = 2'd2;
  localparam OP_STORE = 2'd3;

  localparam S_IDLE           = 3'd0;
  localparam S_START          = 3'd1;
  localparam S_WAIT_BUSY_HIGH = 3'd2;
  localparam S_WAIT_BUSY_LOW  = 3'd3;
  localparam S_FINISH         = 3'd4;

  reg [2:0] state;
  reg [1:0] op;
  reg [15:0] last_flash_addr;


  always @(posedge clk or negedge rst_n)
  begin
    if (!rst_n)
    begin
      state              <= S_IDLE;
      op                 <= OP_NONE;
      mem_rdata          <= 16'h0000;
      fetch_done         <= 1'b0;
      data_done          <= 1'b0;
      mem_stall          <= 1'b0;
      spi_st             <= 1'b0;
      spi_ld             <= 1'b0;
      spi_addr           <= 16'h0000;
      spi_data_in        <= 16'h0000;
      spi_target         <= 1'b0;
      last_flash_addr    <= 16'h0000;
    end
    else
    begin
      fetch_done <= 1'b0;
      data_done  <= 1'b0;
      spi_st     <= 1'b0;
      spi_ld     <= 1'b0;

      case (state)
        S_IDLE:
        begin
          mem_stall <= 1'b0;
          op        <= OP_NONE;

          if (st_req)
          begin
            op          <= OP_STORE;
            spi_target  <= 1'b1;
            spi_addr    <= data_addr;
            spi_data_in <= store_data;
            mem_stall   <= 1'b1;
            state       <= S_START;
          end
          else if (ld_req)
          begin
            op          <= OP_LOAD;
            spi_target  <= 1'b1;
            spi_addr    <= data_addr;
            spi_data_in <= 16'h0000;
            mem_stall   <= 1'b1;
            state       <= S_START;
          end
          else if (fetch_req)
          begin
            op          <= OP_FETCH;
            spi_target  <= 1'b0;
            spi_addr    <= fetch_addr;
            spi_data_in <= 16'h0000;
            mem_stall   <= 1'b1;
            state       <= S_START;
          end
          else if (flash_req)
          begin
            op          <= OP_LOAD;
            spi_target  <= 1'b0;
            spi_addr    <= data_addr;
            spi_data_in <= 16'h0000;
            mem_stall   <= 1'b1;
            state       <= S_START;
          end
        end

        S_START:
        begin
          if (op == OP_STORE)
            spi_st <= 1'b1;
          else
          begin
            spi_ld <= 1'b1;
            
          end
          state <= S_WAIT_BUSY_HIGH;
        end

        S_WAIT_BUSY_HIGH:
          if (spi_busy)
            state <= S_WAIT_BUSY_LOW;

        S_WAIT_BUSY_LOW:
        begin
          if (!spi_busy)
          begin
            if (op != OP_STORE)
              mem_rdata <= spi_data_out;
            state <= S_FINISH;
          end
        end

        S_FINISH:
        begin
          mem_stall <= 1'b0;
          if (op == OP_FETCH)
          begin
            fetch_done         <= 1'b1;
            last_flash_addr    <= spi_addr;
          end
          else
          begin
            data_done          <= 1'b1;
          end
          state <= S_IDLE;
        end

        default:
        begin
          state              <= S_IDLE;
        end
      endcase
    end
  end

endmodule

module debug_core_tiny
(
    input  wire        clk,
    input  wire        rst_n,

    // Tiny register port
    input  wire        reg_wr,
    input  wire [3:0]  reg_addr,
    input  wire [15:0] reg_wdata,
    output reg  [15:0] reg_rdata,

    // CPU status
    input  wire        cpu_dbg_halted,
    input  wire [2:0]  cpu_flags,
    input  wire [15:0] cpu_pc,
    input  wire [15:0] cpu_ir,

    // Debug control outputs
    output reg         dbg_enable,
    output reg         dbg_halt_req,
    output reg         dbg_run_req,
    output reg         dbg_step_req,
    output reg         static_break_enable,

    // One dynamic breakpoint only
    output reg  [15:0] bp0,
    output reg         bp_enable
);

  localparam REG_ID      = 4'h0;
  localparam REG_STATUS  = 4'h1;
  localparam REG_CONTROL = 4'h2;
  localparam REG_FLAGS   = 4'h3;
  localparam REG_PC      = 4'h4;
  localparam REG_IR      = 4'h5;
  localparam REG_BP0     = 4'h8;
  localparam REG_BPCTRL  = 4'h9;

  always @(posedge clk or negedge rst_n)
  begin
    if (!rst_n)
    begin
      dbg_enable           <= 1'b0;
      dbg_halt_req         <= 1'b0;
      dbg_run_req          <= 1'b0;
      dbg_step_req         <= 1'b0;
      static_break_enable  <= 1'b0;
      bp0                  <= 16'h0000;
      bp_enable            <= 1'b0;
    end
    else
    begin
      dbg_run_req  <= 1'b0;
      dbg_step_req <= 1'b0;

      if (cpu_dbg_halted)
        dbg_halt_req <= 1'b0;

      if (reg_wr)
      begin
        case (reg_addr)
          REG_CONTROL:
          begin
            dbg_enable          <= reg_wdata[0];
            static_break_enable <= reg_wdata[5];

            if (!reg_wdata[0])
              dbg_halt_req <= 1'b0;

            if (reg_wdata[1] && reg_wdata[0])
              dbg_halt_req <= 1'b1;

            if (reg_wdata[2] && reg_wdata[0])
            begin
              dbg_run_req  <= 1'b1;
              dbg_halt_req <= 1'b0;
            end

            if (reg_wdata[3] && reg_wdata[0])
            begin
              dbg_step_req <= 1'b1;
              dbg_halt_req <= 1'b0;
            end
          end

          REG_BP0:
            bp0 <= reg_wdata;

          REG_BPCTRL:
            bp_enable <= reg_wdata[0];

          default:
          begin
          end
        endcase
      end
    end
  end

  always @(*)
  begin
    case (reg_addr)
      REG_ID:
        reg_rdata = 16'hDB11;

      REG_STATUS:
        reg_rdata = {
          12'h000,
          bp_enable,
          static_break_enable,
          dbg_enable,
          cpu_dbg_halted
        };

      REG_CONTROL:
        reg_rdata = {
          10'h000,
          static_break_enable,
          1'b0,
          1'b0,
          1'b0,
          dbg_halt_req,
          dbg_enable
        };

      REG_FLAGS:
        reg_rdata = {13'h0000, cpu_flags};

      REG_PC:
        reg_rdata = cpu_pc;

      REG_IR:
        reg_rdata = cpu_ir;

      REG_BP0:
        reg_rdata = bp0;

      REG_BPCTRL:
        reg_rdata = {15'h0000, bp_enable};

      default:
        reg_rdata = 16'h0000;
    endcase
  end

endmodule

module breakpoint_logic_tiny
(
    input  wire        clk,
    input  wire        rst_n,

    input  wire        dbg_enable,
    input  wire        dbg_halted,
    input  wire        dbg_run_req,
    input  wire        dbg_step_req,
    input  wire        execute_now_pulse,

    input  wire [15:0] pc,
    input  wire [15:0] bp0,
    input  wire        bp_enable,

    input  wire        instr_is_brk,
    input  wire        static_break_enable,

    output wire        dbg_break_hit,
    output wire        dbg_break_after_exec
);

    reg bp_resume_mask;
    wire resume_cmd;
    wire bp_raw_hit;

    assign resume_cmd = dbg_run_req | dbg_step_req;
    assign bp_raw_hit = dbg_enable & bp_enable & (pc == bp0);

    assign dbg_break_hit = bp_raw_hit & ~bp_resume_mask;
    assign dbg_break_after_exec = dbg_enable & static_break_enable & instr_is_brk;

    always @(posedge clk or negedge rst_n)
    begin
        if (!rst_n)
            bp_resume_mask <= 1'b0;
        else if (execute_now_pulse)
            bp_resume_mask <= 1'b0;
        else if (dbg_halted & resume_cmd)
            bp_resume_mask <= 1'b1;
    end

endmodule

module DIG_Add
#(
    parameter Bits = 1
)
(
    input [(Bits-1):0] a,
    input [(Bits-1):0] b,
    input c_i,
    output [(Bits - 1):0] s,
    output c_o
);
   wire [Bits:0] temp;

   assign temp = a + b + c_i;
   assign s = temp [(Bits-1):0];
   assign c_o = temp[Bits];
endmodule



module singExtend (
  input [7:0] inst,
  output [15:0] \4S , // The four bits taken from Rs.
  output [15:0] \8SD , // The eight bits taken from Rs,Rd with sign extension.
  output [15:0] \4D  // The four bits taken from Rd.

);
  wire s0;
  assign \4D [3:0] = inst[7:4];
  assign \4D [15:4] = 12'b0;
  assign \4S [3:0] = inst[3:0];
  assign \4S [15:4] = 12'b0;
  assign s0 = inst[7];
  assign \8SD [6:0] = inst[6:0];
  assign \8SD [7] = s0;
  assign \8SD [8] = s0;
  assign \8SD [9] = s0;
  assign \8SD [10] = s0;
  assign \8SD [11] = s0;
  assign \8SD [12] = s0;
  assign \8SD [13] = s0;
  assign \8SD [14] = s0;
  assign \8SD [15] = s0;
endmodule

