module Alu (
  input [15:0] A,
  input [15:0] B,
  input carryIn,
  input [5:0] AluOp,
  output [15:0] Out,
  output Neg,
  output Zero,
  output CarryOut
);
  wire [3:0] s0;
  wire [15:0] s1;
  wire [15:0] s2;
  wire [15:0] s3;
  wire [15:0] s4;
  wire [15:0] s5;
  wire [15:0] s6;
  wire [15:0] s7;
  wire [15:0] s8;
  wire [15:0] s9;
  wire [15:0] s10;
  wire [15:0] s11;
  wire [15:0] s12;
  wire [15:0] Out_temp;
  wire [3:0] s13;
  wire s14;
  wire s15;
  wire s16;
  wire s17;
  wire s18;
  wire [4:0] sel;
  wire s19;
  wire s20;
  assign s3 = (A & B);
  assign s4 = (A | B);
  assign s5 = (A ^ B);
  assign s19 = (AluOp[5] & carryIn);
  assign s6 = ~ A;
  DIG_Neg #(
    .Bits(16)
  )
  DIG_Neg_i0 (
    .in( A ),
    .out( s7 )
  );
  assign s12[3:0] = A[7:4];
  assign s12[7:4] = A[3:0];
  assign s12[11:8] = A[15:12];
  assign s12[15:12] = A[11:8];
  assign s11[7:0] = A[15:8];
  assign s11[15:8] = A[7:0];
  assign sel = AluOp[4:0];
  assign s18 = A[0];
  assign s20 = A[15];
  assign s17 = A[0];
  assign s16 = A[15];
  DIG_Add #(
    .Bits(16)
  )
  DIG_Add_i1 (
    .a( A ),
    .b( B ),
    .c_i( s19 ),
    .s( s1 ),
    .c_o( s14 )
  );
  DIG_Sub #(
    .Bits(16)
  )
  DIG_Sub_i2 (
    .a( A ),
    .b( B ),
    .c_i( s19 ),
    .s( s2 ),
    .c_o( s15 )
  );
  assign s10[13:0] = A[14:1];
  assign s10[14] = s20;
  assign s10[15] = s20;
  assign s9[14:0] = A[15:1];
  assign s9[15] = s19;
  assign s8[0] = s19;
  assign s8[15:1] = A[14:0];
  assign s13 = sel[3:0];
  assign s0 = sel[3:0];
  Mux_16x1_NBits #(
    .Bits(16)
  )
  Mux_16x1_NBits_i3 (
    .sel( s0 ),
    .in_0( B ),
    .in_1( s1 ),
    .in_2( s2 ),
    .in_3( s3 ),
    .in_4( s4 ),
    .in_5( s5 ),
    .in_6( s6 ),
    .in_7( s7 ),
    .in_8( s8 ),
    .in_9( s9 ),
    .in_10( s10 ),
    .in_11( s11 ),
    .in_12( s12 ),
    .in_13( A ),
    .in_14( 16'b0 ),
    .in_15( 16'b0 ),
    .out( Out_temp )
  );
  Mux_16x1 Mux_16x1_i4 (
    .sel( s13 ),
    .in_0( 1'b0 ),
    .in_1( s14 ),
    .in_2( s15 ),
    .in_3( 1'b0 ),
    .in_4( 1'b0 ),
    .in_5( 1'b0 ),
    .in_6( 1'b0 ),
    .in_7( 1'b0 ),
    .in_8( s16 ),
    .in_9( s17 ),
    .in_10( s18 ),
    .in_11( 1'b0 ),
    .in_12( 1'b0 ),
    .in_13( 1'b0 ),
    .in_14( 1'b0 ),
    .in_15( 1'b0 ),
    .out( CarryOut )
  );
